def assert_required_fields(response: dict, required: list) -> None:
    for field in required:
        assert field in response, f"Missing required field: '{field}'"

# Example usage
response = {"id": 42, "email": "user@example.com"}
required = ["id", "email", "role"]
assert_required_fields(response, required)

def validate_schema(response: dict, schema: dict) -> None:
    for field, expected_type in schema.items():
        assert field in response, f"Missing field: '{field}'"
        actual = response[field]
        assert isinstance(actual, expected_type), (
            f"Field '{field}': expected {expected_type}, got {type(actual)}"
        )

# Example usage
schema = {"id": int, "name": str, "active": bool}
response = {"id": "abc", "name": "Alice", "active": True}
validate_schema(response, schema)

import pytest
import requests

BASE_URL = "https://api.example.com"

@pytest.fixture
def api_user():
    payload = {
        "name": "Test User",
        "email": "testuser@example.com",
        "password": "Secure123!"
    }
    create_resp = requests.post(
        f"{BASE_URL}/users",
        json=payload,
        headers={"Content-Type": "application/json"}
    )
    assert create_resp.status_code == 201, (
        f"Setup failed: {create_resp.status_code} {create_resp.text}"
    )
    user = create_resp.json()

    yield user  # Test runs here

    # Teardown
    requests.delete(
        f"{BASE_URL}/users/{user['id']}",
        headers={"Content-Type": "application/json"}
    )

# Example test
def test_user_has_id(api_user):
    assert "id" in api_user
    assert api_user["email"] == "testuser@example.com"
